import { httpBatchLink } from '@trpc/client';
import { createTRPCNext } from '@trpc/next';
import type { AppRouter } from '../server/routers';
import superjson from 'superjson';

function getBaseUrl() {
  if (typeof window !== 'undefined')
    return '';
  return `http://localhost:${process.env.PORT ?? 3000}`;
}

export const trpc = createTRPCNext<AppRouter>({
  config(opts) {
    return {
      links: [
        httpBatchLink({
          transformer: superjson,
          url: `${getBaseUrl()}/api/trpc`,
        }),
      ],
    };
  },
  ssr: false,
});

import { inferAsyncReturnType, type TRPCRequestInfo } from '@trpc/server';
import * as trpcNext from '@trpc/server/adapters/next';

export async function createContext(
  opts: trpcNext.CreateNextContextOptions & { info?: TRPCRequestInfo },
) {
  const rawInput = await opts.info?.calls?.[0]?.getRawInput?.();

  return {
    req: opts.req,
    res: opts.res,
    rawInput,
  };
}

export type Context = inferAsyncReturnType<typeof createContext>;

import type { AppProps } from 'next';
import { trpc } from '../utils/trpc';

function MyApp({ Component, pageProps }: AppProps) {
  return <Component {...pageProps} />;
}

export default trpc.withTRPC(MyApp);

